  1→import { FormEvent, MouseEvent, useEffect, useMemo, useRef, useState } from "react";
  2→import {
  3→  Chat,
  4→  ChatSuggestions,
  5→  ChatInput,
  6→  SessionMessagePanel,
  7→  SessionMessages,
  8→  SessionMessagesHeader,
  9→  type MentionItem,
 10→  type ChatInputRef,
 11→  type Session,
 12→  type Suggestion,
 13→  type SlashCommandItem,
 14→} from "reachat";
 15→import type {
 16→  ChatMessageResponse,
 17→  CreateWorkspaceRequest,
 18→  CreateWorkspaceResponse,
 19→  OnboardingAction,
 20→  OnboardingSeedItem,
 21→  SearchEntityResponse,
 22→  StreamEvent as ChatStreamEvent,
 23→  WorkspaceBootstrapResponse,
 24→  WorkspaceConversationSidebarResponse,
 25→  WorkspaceConversationResponse,
 26→} from "../../shared/contracts";
 27→import { chatComponentCatalog } from "../chat-component-catalog";
 28→
 29→type WorkspaceState = {
 30→  id: string;
 31→  name: string;
 32→  onboardingComplete: boolean;
 33→  onboardingState: "active" | "summary_pending" | "complete";
 34→  conversationId: string;
 35→};
 36→
 37→const COMMAND_ITEMS: SlashCommandItem[] = [
 38→  {
 39→    id: "task",
 40→    label: "task",
 41→    description: "Record a task",
 42→    type: "insert",
 43→    value: "task: ",
 44→  },
 45→  {
 46→    id: "decision",
 47→    label: "decision",
 48→    description: "Record a decision",
 49→    type: "insert",
 50→    value: "decision: ",
 51→  },
 52→  {
 53→    id: "question",
 54→    label: "question",
 55→    description: "Record an open question",
 56→    type: "insert",
 57→    value: "question: ",
 58→  },
 59→];
 60→
 61→const ACTIVE_WORKSPACE_STORAGE_KEY = "brain.activeWorkspaceId";
 62→
 63→export function ChatPage() {
 64→  const [workspace, setWorkspace] = useState<WorkspaceState | undefined>();
 65→  const [createWorkspaceName, setCreateWorkspaceName] = useState("");
 66→  const [createOwnerName, setCreateOwnerName] = useState("");
 67→  const [isCreatingWorkspace, setIsCreatingWorkspace] = useState(false);
 68→  const [isBootstrapping, setIsBootstrapping] = useState(false);
 69→  const [sessions, setSessions] = useState<Session[]>([
 70→    {
 71→      id: "main",
 72→      title: "Workspace Chat",
 73→      createdAt: new Date(),
 74→      updatedAt: new Date(),
 75→      conversations: [],
 76→    },
 77→  ]);
 78→  const [activeSessionId] = useState("main");
 79→  const [backendConversationId, setBackendConversationId] = useState<string | undefined>();
 80→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 81→  const [sidebar, setSidebar] = useState<WorkspaceConversationSidebarResponse | undefined>();
 82→  const [isLoading, setIsLoading] = useState(false);
 83→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 84→  const [seedItems, setSeedItems] = useState<OnboardingSeedItem[]>([]);
 85→  const [isSeedPanelOpen, setIsSeedPanelOpen] = useState(false);
 86→  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
 87→  const [pendingFile, setPendingFile] = useState<File | undefined>();
 88→  const streamRef = useRef<EventSource | undefined>(undefined);
 89→  const chatInputRef = useRef<ChatInputRef | null>(null);
 90→  const canCreateWorkspace =
 91→    createWorkspaceName.trim().length > 0 && createOwnerName.trim().length > 0;
 92→
 93→  const activeSession = useMemo(
 94→    () => sessions.find((session) => session.id === activeSessionId),
 95→    [sessions, activeSessionId],
 96→  );
 97→
 98→  useEffect(() => {
 99→    const existingWorkspaceId = window.localStorage.getItem(ACTIVE_WORKSPACE_STORAGE_KEY);
100→    if (!existingWorkspaceId) {
101→      return;
102→    }
103→
104→    void bootstrapWorkspace(existingWorkspaceId);
105→  }, []);
106→
107→  if (!activeSession) {
108→    throw new Error("active session missing");
109→  }
110→
111→  async function refreshSidebar(workspaceId: string) {
112→    try {
113→      const response = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/sidebar`);
114→      if (response.ok) {
115→        const payload = (await response.json()) as WorkspaceConversationSidebarResponse;
116→        setSidebar(payload);
117→      }
118→    } catch {
119→      // Sidebar refresh is non-critical; silently ignore
120→    }
121→  }
122→
123→  async function loadConversation(workspaceId: string, conversationId: string) {
124→    try {
125→      const response = await fetch(
126→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(conversationId)}`,
127→      );
128→      if (!response.ok) {
129→        const body = await response.text();
130→        setErrorMessage(body);
131→        return;
132→      }
133→
134→      const payload = (await response.json()) as WorkspaceConversationResponse;
135→      const conversations: Session["conversations"] = [];
136→      let latestSuggestions: string[] = [];
137→
138→      for (const message of payload.messages) {
139→        if (message.role === "user") {
140→          conversations.push({
141→            id: message.id,
142→            question: message.text,
143→            createdAt: new Date(message.createdAt),
144→          });
145→          continue;
146→        }
147→
148→        const last = conversations[conversations.length - 1];
149→        if (last && !last.response) {
150→          last.response = message.text;
151→          last.updatedAt = new Date(message.createdAt);
152→          latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
153→          continue;
154→        }
155→
156→        conversations.push({
157→          id: `assistant-${message.id}`,
158→          question: "System kickoff",
159→          response: message.text,
160→          createdAt: new Date(message.createdAt),
161→        });
162→        latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
163→      }
164→
165→      setSessions([
166→        {
167→          id: "main",
168→          title: workspace?.name ?? "Workspace Chat",
169→          createdAt: new Date(),
170→          updatedAt: new Date(),
171→          conversations,
172→        },
173→      ]);
174→
175→      setSuggestions(
176→        latestSuggestions.map((content, index) => ({
177→          id: `conv-suggestion-${index}-${content}`,
178→          content,
179→        })),
180→      );
181→
182→      setActiveConversationId(conversationId);
183→      setBackendConversationId(conversationId);
184→    } catch (error) {
185→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
186→      setErrorMessage(messageText);
187→    }
188→  }
189→
190→  async function bootstrapWorkspace(workspaceId: string) {
191→    setIsBootstrapping(true);
192→    setErrorMessage(undefined);
193→
194→    let response: Response;
195→    try {
196→      response = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/bootstrap`);
197→    } catch (error) {
198→      const messageText = error instanceof Error ? error.message : "Network error";
199→      setErrorMessage(messageText);
200→      setIsBootstrapping(false);
201→      return;
202→    }
203→
204→    if (!response.ok) {
205→      if (response.status === 404) {
206→        window.localStorage.removeItem(ACTIVE_WORKSPACE_STORAGE_KEY);
207→        setWorkspace(undefined);
208→      }
209→      const body = await response.text();
210→      setErrorMessage(body);
211→      setIsBootstrapping(false);
212→      return;
213→    }
214→
215→    const payload = (await response.json()) as WorkspaceBootstrapResponse;
216→    applyBootstrapPayload(payload);
217→    setIsBootstrapping(false);
218→  }
219→
220→  function applyBootstrapPayload(payload: WorkspaceBootstrapResponse) {
221→    const conversations: Session["conversations"] = [];
222→    let latestSuggestions: string[] = [];
223→
224→    for (const message of payload.messages) {
225→      if (message.role === "user") {
226→        conversations.push({
227→          id: message.id,
228→          question: message.text,
229→          createdAt: new Date(message.createdAt),
230→        });
231→        continue;
232→      }
233→
234→      const last = conversations[conversations.length - 1];
235→      if (last && !last.response) {
236→        last.response = message.text;
237→        last.updatedAt = new Date(message.createdAt);
238→        latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
239→        continue;
240→      }
241→
242→      conversations.push({
243→        id: `assistant-${message.id}`,
244→        question: "System kickoff",
245→        response: message.text,
246→        createdAt: new Date(message.createdAt),
247→      });
248→      latestSuggestions = message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
249→    }
250→
251→    setSessions([
252→      {
253→        id: "main",
254→        title: payload.workspaceName,
255→        createdAt: new Date(),
256→        updatedAt: new Date(),
257→        conversations,
258→      },
259→    ]);
260→
261→    setSeedItems(payload.seeds);
262→    setSuggestions(
263→      latestSuggestions.map((content, index) => ({
264→        id: `bootstrap-suggestion-${index}-${content}`,
265→        content,
266→      })),
267→    );
268→    setBackendConversationId(payload.conversationId);
269→    setActiveConversationId(payload.conversationId);
270→    setSidebar(payload.sidebar);
271→    setWorkspace({
272→      id: payload.workspaceId,
273→      name: payload.workspaceName,
274→      onboardingComplete: payload.onboardingComplete,
275→      onboardingState: payload.onboardingState,
276→      conversationId: payload.conversationId,
277→    });
278→  }
279→
280→  function onNewConversation() {
281→    setActiveConversationId(undefined);
282→    setBackendConversationId(undefined);
283→    setSessions([
284→      {
285→        id: "main",
286→        title: workspace?.name ?? "Workspace Chat",
287→        createdAt: new Date(),
288→        updatedAt: new Date(),
289→        conversations: [],
290→      },
291→    ]);
292→    setSuggestions([]);
293→    setErrorMessage(undefined);
294→  }
295→
296→  function onSelectConversation(conversationId: string) {
297→    if (conversationId === activeConversationId || isLoading || !workspace) {
298→      return;
299→    }
300→
301→    void loadConversation(workspace.id, conversationId);
302→  }
303→
304→  async function searchMentions(query: string): Promise<MentionItem[]> {
305→    if (!workspace) {
306→      return [];
307→    }
308→
309→    const response = await fetch(
310→      `/api/entities/search?q=${encodeURIComponent(query)}&workspaceId=${encodeURIComponent(workspace.id)}&limit=8`,
311→    );
312→    if (!response.ok) {
313→      throw new Error(`entity search failed: ${response.status}`);
314→    }
315→
316→    const rows = (await response.json()) as SearchEntityResponse[];
317→    return rows.map((row) => ({
318→      id: row.id,
319→      label: `${row.kind}: ${row.text.slice(0, 48)}`,
320→      description: `confidence ${row.confidence.toFixed(2)}`,
321→      value: `@${row.id}`,
322→    }));
323→  }
324→
325→  async function onCreateWorkspace(event: FormEvent<HTMLFormElement>) {
326→    event.preventDefault();
327→
328→    const name = createWorkspaceName.trim();
329→    const ownerDisplayName = createOwnerName.trim();
330→    if (isCreatingWorkspace) {
331→      return;
332→    }
333→
334→    if (!name || !ownerDisplayName) {
335→      setErrorMessage("Workspace name and owner display name are required");
336→      return;
337→    }
338→
339→    setErrorMessage(undefined);
340→    setIsCreatingWorkspace(true);
341→
342→    const requestBody: CreateWorkspaceRequest = {
343→      name,
344→      ownerDisplayName,
345→    };
346→
347→    try {
348→      const response = await fetch("/api/workspaces", {
349→        method: "POST",
350→        headers: {
351→          "Content-Type": "application/json",
352→        },
353→        body: JSON.stringify(requestBody),
354→      });
355→
356→      if (!response.ok) {
357→        const body = await response.text();
358→        setErrorMessage(body);
359→        return;
360→      }
361→
362→      const payload = (await response.json()) as Partial<CreateWorkspaceResponse>;
363→      if (typeof payload.workspaceId !== "string" || payload.workspaceId.trim().length === 0) {
364→        throw new Error("create workspace response is missing workspaceId");
365→      }
366→
367→      window.localStorage.setItem(ACTIVE_WORKSPACE_STORAGE_KEY, payload.workspaceId);
368→      await bootstrapWorkspace(payload.workspaceId);
369→      setCreateWorkspaceName("");
370→      setCreateOwnerName("");
371→    } catch (error) {
372→      const messageText = error instanceof Error ? error.message : "Workspace creation failed";
373→      setErrorMessage(messageText);
374→    } finally {
375→      setIsCreatingWorkspace(false);
376→    }
377→  }
378→
379→  function onUploadFile(file: File) {
380→    setPendingFile(file);
381→  }
382→
383→  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
384→    if (!pendingFile || isLoading) {
385→      return;
386→    }
387→
388→    const target = event.target;
389→    if (!(target instanceof Element)) {
390→      return;
391→    }
392→
393→    const sendButton = target.closest("button[title='Send']");
394→    if (!sendButton) {
395→      return;
396→    }
397→
398→    const currentMessage = chatInputRef.current?.getValue().trim() ?? "";
399→    if (currentMessage.length > 0) {
400→      return;
401→    }
402→
403→    event.preventDefault();
404→    event.stopPropagation();
405→    void onSendMessage("");
406→  }
407→
408→  async function onSendMessage(message: string, options?: { onboardingAction?: OnboardingAction }) {
409→    if (isLoading || !workspace) {
410→      return;
411→    }
412→
413→    const text = message.trim();
414→    if (!text && !pendingFile) {
415→      return;
416→    }
417→
418→    setErrorMessage(undefined);
419→    setIsLoading(true);
420→    setSuggestions([]);
421→
422→    const clientMessageId = crypto.randomUUID();
423→    const currentAttachment = pendingFile;
424→
425→    setSessions((existing) =>
426→      existing.map((session) =>
427→        session.id === activeSessionId
428→          ? {
429→              ...session,
430→              updatedAt: new Date(),
431→              conversations: [
432→                ...session.conversations,
433→                {
434→                  id: clientMessageId,
435→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
436→                  createdAt: new Date(),
437→                  ...(currentAttachment
438→                    ? {
439→                        files: [
440→                          {
441→                            name: currentAttachment.name,
442→                            type: currentAttachment.type,
443→                            size: currentAttachment.size,
444→                          },
445→                        ],
446→                      }
447→                    : {}),
448→                },
449→              ],
450→            }
451→          : session,
452→      ),
453→    );
454→
455→    let response: Response;
456→    try {
457→      if (currentAttachment) {
458→        const formData = new FormData();
459→        formData.set("clientMessageId", clientMessageId);
460→        formData.set("workspaceId", workspace.id);
461→        formData.set("text", text);
462→        if (backendConversationId) {
463→          formData.set("conversationId", backendConversationId);
464→        }
465→        if (options?.onboardingAction) {
466→          formData.set("onboardingAction", options.onboardingAction);
467→        }
468→        formData.set("file", currentAttachment);
469→
470→        response = await fetch("/api/chat/messages", {
471→          method: "POST",
472→          body: formData,
473→        });
474→      } else {
475→        response = await fetch("/api/chat/messages", {
476→          method: "POST",
477→          headers: {
478→            "Content-Type": "application/json",
479→          },
480→          body: JSON.stringify({
481→            clientMessageId,
482→            workspaceId: workspace.id,
483→            text,
484→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
485→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
486→          }),
487→        });
488→      }
489→    } catch (error) {
490→      const messageText = error instanceof Error ? error.message : "Network error";
491→      setErrorMessage(messageText);
492→      setIsLoading(false);
493→      return;
494→    } finally {
495→      setPendingFile(undefined);
496→    }
497→
498→    if (!response.ok) {
499→      const body = await response.text();
500→      setErrorMessage(body);
501→      setIsLoading(false);
502→      return;
503→    }
504→
505→    const payload = (await response.json()) as ChatMessageResponse;
506→    const isNewConversation = !backendConversationId;
507→    setBackendConversationId(payload.conversationId);
508→    if (isNewConversation) {
509→      setActiveConversationId(payload.conversationId);
510→    }
511→
512→    if (streamRef.current) {
513→      streamRef.current.close();
514→      streamRef.current = undefined;
515→    }
516→
517→    let streamedText = "";
518→
519→    const stream = new EventSource(payload.streamUrl);
520→    streamRef.current = stream;
521→
522→    stream.onmessage = (messageEvent) => {
523→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
524→
525→      if (parsed.type === "token") {
526→        streamedText = `${streamedText}${parsed.token}`;
527→        setSessions((existing) =>
528→          existing.map((session) =>
529→            session.id === activeSessionId
530→              ? {
531→                  ...session,
532→                  conversations: session.conversations.map((conversation) =>
533→                    conversation.id === clientMessageId
534→                      ? {
535→                          ...conversation,
536→                          response: streamedText,
537→                          updatedAt: new Date(),
538→                        }
539→                      : conversation,
540→                  ),
541→                }
542→              : session,
543→          ),
544→        );
545→        return;
546→      }
547→
548→      if (parsed.type === "assistant_message") {
549→        streamedText = parsed.text;
550→        setSuggestions(
551→          (parsed.suggestions ?? []).map((content, index) => ({
552→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
553→            content,
554→          })),
555→        );
556→        setSessions((existing) =>
557→          existing.map((session) =>
558→            session.id === activeSessionId
559→              ? {
560→                  ...session,
561→                  conversations: session.conversations.map((conversation) =>
562→                    conversation.id === clientMessageId
563→                      ? {
564→                          ...conversation,
565→                          response: streamedText,
566→                          updatedAt: new Date(),
567→                        }
568→                      : conversation,
569→                  ),
570→                }
571→              : session,
572→          ),
573→        );
574→        return;
575→      }
576→
577→      if (parsed.type === "onboarding_seed") {
578→        setSeedItems((existing) => {
579→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
580→          for (const seed of parsed.seeds) {
581→            deduped.set(`${seed.id}:${seed.sourceKind}:${seed.sourceId}`, seed);
582→          }
583→          return [...deduped.values()];
584→        });
585→        return;
586→      }
587→
588→      if (parsed.type === "onboarding_state") {
589→        setWorkspace((existing) =>
590→          existing
591→            ? {
592→                ...existing,
593→                onboardingState: parsed.onboardingState,
594→                onboardingComplete: parsed.onboardingState === "complete",
595→              }
596→            : existing,
597→        );
598→        return;
599→      }
600→
601→      if (parsed.type === "error") {
602→        setErrorMessage(parsed.error);
603→        setIsLoading(false);
604→        stream.close();
605→        streamRef.current = undefined;
606→        return;
607→      }
608→
609→      if (parsed.type === "done") {
610→        setSessions((existing) =>
611→          existing.map((session) =>
612→            session.id === activeSessionId
613→              ? {
614→                  ...session,
615→                  updatedAt: new Date(),
616→                  conversations: session.conversations.map((conversation) =>
617→                    conversation.id === clientMessageId
618→                      ? {
619→                          ...conversation,
620→                          response: streamedText,
621→                          updatedAt: new Date(),
622→                        }
623→                      : conversation,
624→                  ),
625→                }
626→              : session,
627→          ),
628→        );
629→
630→        setIsLoading(false);
631→        stream.close();
632→        streamRef.current = undefined;
633→
634→        // Refresh sidebar after stream completes
635→        if (workspace) {
636→          void refreshSidebar(workspace.id);
637→        }
638→      }
639→    };
640→
641→    stream.onerror = () => {
642→      setErrorMessage("SSE stream disconnected");
643→      setIsLoading(false);
644→      stream.close();
645→      streamRef.current = undefined;
646→    };
647→  }
