  color: #1d3f62;
}

.entity-confidence {
  margin: 0;
  font-size: 0.72rem;
  color: #476482;
}

.extraction-summary-meta {
  margin: 0.5rem 0 0;
  font-size: 0.72rem;
  color: #476482;
}

@media (max-width: 700px) {
  .app-shell {
    padding: 0.8rem 0.6rem 1.2rem;
