}

.reachat-page button[title="Upload"] {
  width: 2rem;
  height: 2rem;
  padding: 0;
  border: 1px solid #9ab9dd;
  border-radius: 999px;
  background: #eef5ff;
  color: #1d4e84;
  display: inline-flex;
  align-items: center;
