}

.reachat-page button[title="Upload"]:hover {
  background: #dfebfc;
  color: #154378;
}

.reachat-page button[title="Upload"] svg {
  width: 1rem;
  height: 1rem;
  display: block;
}

.error-message {
  margin-top: 0.75rem;
  color: #8a1020;
  font-weight: 600;
}

.extraction-block {
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
