  border-color: rgba(14, 110, 69, 0.25);
}

.relationship-badge {
  background: rgba(9, 86, 171, 0.1);
  color: #0e4f96;
  border-color: rgba(9, 86, 171, 0.24);
}

.extraction-summary {
  margin-top: 0.7rem;
  border: 1px solid #d6e6fa;
  border-radius: 12px;
  background: #f8fbff;
  padding: 0.65rem;
}

.extraction-summary-title {
  margin: 0 0 0.45rem;
  font-size: 0.78rem;
  font-weight: 700;
  color: #1f527f;
}

.extraction-summary-grid {
  display: grid;
  gap: 0.45rem;
}

.entity-card {
  border: 1px solid #d6e4f6;
  border-radius: 10px;
  background: #fff;
  padding: 0.5rem 0.55rem;
}

.entity-card-header {
  display: flex;
  justify-content: space-between;
  gap: 0.45rem;
}

.entity-kind {
  font-size: 0.67rem;
  font-weight: 700;
  color: #185389;
  text-transform: uppercase;
}

.entity-status {
  font-size: 0.67rem;
  font-weight: 700;
  color: #2f6b2e;
  text-transform: uppercase;
}

.entity-name {
  margin: 0.2rem 0;
  font-size: 0.84rem;
  font-weight: 600;
  color: #1d3f62;
}

.entity-confidence {
  margin: 0;
  font-size: 0.72rem;
  color: #476482;
}

.extraction-summary-meta {
  margin: 0.5rem 0 0;
  font-size: 0.72rem;
  color: #476482;
}

@media (max-width: 700px) {
  .app-shell {
    padding: 0.8rem 0.6rem 1.2rem;
  }

  .reachat-page {
    min-height: 78vh;
    padding: 0.35rem;
  }

  .workspace-layout {
    grid-template-columns: 1fr;
  }

  .chat-main--with-seeds {
    grid-template-columns: 1fr;
  }

  .conversation-sidebar {
    max-height: 30vh;
  }

  .seed-panel ul {
    max-height: 28vh;
  }

  .workspace-toolbar {
    flex-direction: column;
    align-items: flex-start;
  }
}

