import { useCallback, useEffect, useRef, useState } from "react";
import type { GraphCanvasRef } from "reagraph";

type ProjectOption = {
  id: string;
  name: string;
};

export function GraphToolbar({
  workspaceId,
  viewMode,
  projectId,
  depth,
  onViewModeChange,
  onProjectChange,
  onDepthChange,
  graphRef,
}: {
  workspaceId: string;
  viewMode: "project" | "focused";
  projectId: string | undefined;
  depth: number;
  onViewModeChange: (mode: "project" | "focused") => void;
  onProjectChange: (projectId: string) => void;
  onDepthChange: (depth: number) => void;
  graphRef?: React.RefObject<GraphCanvasRef | null>;
}) {
  const [projects, setProjects] = useState<ProjectOption[]>([]);

  useEffect(() => {
    fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/sidebar`)
      .then(async (response) => {
        if (!response.ok) return;
        const data = await response.json();
        const groups = (data.groups ?? []) as Array<{ projectId: string; projectName: string }>;
        setProjects(groups.map((g) => ({ id: g.projectId, name: g.projectName })));
      })
      .catch(() => {});
  }, [workspaceId]);

  const handleFit = useCallback(() => {
    graphRef?.current?.fitNodesInView();
  }, [graphRef]);

  return (
    <div className="graph-toolbar">
      <select
        value={projectId ?? ""}
        onChange={(e) => {
          if (e.target.value) {
            onProjectChange(e.target.value);
          }
        }}
      >
        <option value="">All projects</option>
        {projects.map((p) => (
          <option key={p.id} value={p.id}>
            {p.name}
          </option>
        ))}
      </select>

      <select
        value={viewMode}
        onChange={(e) => onViewModeChange(e.target.value as "project" | "focused")}
      >
        <option value="project">Project view</option>
        <option value="focused">Focused view</option>
      </select>

      {viewMode === "focused" ? (
        <label>
          Depth
          <input
            type="range"
            min={1}
            max={3}
            step={1}
            value={depth}
            onChange={(e) => onDepthChange(Number(e.target.value))}
          />
          <span>{depth}</span>
        </label>
      ) : undefined}

      <button type="button" onClick={handleFit}>
        Fit
      </button>
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import { GraphCanvas, type GraphCanvasRef } from "reagraph";
import type { GraphResponse, ReagraphNode, ReagraphEdge } from "../../../shared/contracts";
import { edgeStyle } from "./graph-theme";

export function KnowledgeGraph({
  workspaceId,
  projectId,
  centerId,
  depth,
  selectedId,
  onNodeClick,
}: {
  workspaceId: string;
  projectId?: string;
  centerId?: string;
  depth: number;
  selectedId?: string;
  onNodeClick: (nodeId: string) => void;
}) {
  const [data, setData] = useState<GraphResponse | undefined>();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | undefined>();
  const graphRef = useRef<GraphCanvasRef>(null);

  useEffect(() => {
    setLoading(true);
    setError(undefined);

    const params = new URLSearchParams();
    if (centerId) {
      params.set("center", centerId);
      params.set("depth", String(depth));
    } else if (projectId) {
      params.set("project", projectId);
    }

    const url = `/api/graph/${encodeURIComponent(workspaceId)}${params.toString() ? `?${params}` : ""}`;

    fetch(url)
      .then(async (response) => {
        if (!response.ok) {
          throw new Error(await response.text());
        }
        return response.json() as Promise<GraphResponse>;
      })
      .then((result) => {
        setData(result);
        setLoading(false);
      })
      .catch((err) => {
        setError(err instanceof Error ? err.message : "Failed to load graph");
        setLoading(false);
      });
  }, [workspaceId, projectId, centerId, depth]);

  if (loading) {
    return (
      <div className="graph-canvas">
        <div className="graph-empty">Loading graph...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="graph-canvas">
        <div className="graph-empty">{error}</div>
      </div>
    );
  }

  if (!data || (data.nodes.length === 0)) {
    return (
      <div className="graph-canvas">
        <div className="graph-empty">
          <p>Your graph will grow as you have more conversations.</p>
        </div>
      </div>
    );
  }

  const styledEdges: ReagraphEdge[] = data.edges.map((edge) => {
    const style = edgeStyle(edge.data.type);
    return {
      ...edge,
      fill: style.stroke,
      opacity: style.opacity,
    } as ReagraphEdge;
  });

  return (
    <div className="graph-canvas">
      <GraphCanvas
        ref={graphRef}
        nodes={data.nodes as any}
        edges={styledEdges as any}
        selections={selectedId ? [selectedId] : []}
        layoutType="forceDirected2d"
        sizingType="attribute"
        sizingAttribute="connectionCount"
        labelType="auto"
        onNodeClick={(node: { id: string }) => onNodeClick(node.id)}
      />
    </div>
  );
}

