 27→
 28→  const workspaceHandlers = createWorkspaceRouteHandlers(deps);
 29→  const chatHandlers = createChatIngressHandlers(deps);
 30→  const entitySearchHandler = createEntitySearchHandler(deps);
 31→
 32→  const server = Bun.serve({
 33→    port: config.port,
 34→    idleTimeout: 0,
 35→    routes: {
 36→      "/healthz": {
 37→        GET: withRequestLogging("GET /healthz", "GET", async () => jsonResponse({ status: "ok" }, 200)),
 38→      },
 39→      "/api/workspaces": {
 40→        POST: withRequestLogging("POST /api/workspaces", "POST", (request) => workspaceHandlers.handleCreateWorkspace(request)),
 41→      },
 42→      "/api/workspaces/:workspaceId/bootstrap": {
 43→        GET: withRequestLogging(
