408→  async function onSendMessage(message: string, options?: { onboardingAction?: OnboardingAction }) {
409→    if (isLoading || !workspace) {
410→      return;
411→    }
412→
413→    const text = message.trim();
414→    if (!text && !pendingFile) {
415→      return;
416→    }
417→
418→    setErrorMessage(undefined);
419→    setIsLoading(true);
420→    setSuggestions([]);
421→
422→    const clientMessageId = crypto.randomUUID();
423→    const currentAttachment = pendingFile;
424→
425→    setSessions((existing) =>
426→      existing.map((session) =>
427→        session.id === activeSessionId
428→          ? {
429→              ...session,
430→              updatedAt: new Date(),
431→              conversations: [
432→                ...session.conversations,
433→                {
434→                  id: clientMessageId,
435→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
436→                  createdAt: new Date(),
437→                  ...(currentAttachment
438→                    ? {
439→                        files: [
440→                          {
441→                            name: currentAttachment.name,
442→                            type: currentAttachment.type,
443→                            size: currentAttachment.size,
444→                          },
445→                        ],
446→                      }
447→                    : {}),
448→                },
449→              ],
450→            }
451→          : session,
452→      ),
453→    );
454→
455→    let response: Response;
456→    try {
457→      if (currentAttachment) {
458→        const formData = new FormData();
459→        formData.set("clientMessageId", clientMessageId);
460→        formData.set("workspaceId", workspace.id);
461→        formData.set("text", text);
462→        if (backendConversationId) {
463→          formData.set("conversationId", backendConversationId);
464→        }
465→        if (options?.onboardingAction) {
466→          formData.set("onboardingAction", options.onboardingAction);
467→        }
468→        formData.set("file", currentAttachment);
469→
470→        response = await fetch("/api/chat/messages", {
471→          method: "POST",
472→          body: formData,
473→        });
474→      } else {
475→        response = await fetch("/api/chat/messages", {
476→          method: "POST",
477→          headers: {
478→            "Content-Type": "application/json",
479→          },
480→          body: JSON.stringify({
481→            clientMessageId,
482→            workspaceId: workspace.id,
483→            text,
484→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
485→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
486→          }),
487→        });
488→      }
489→    } catch (error) {
490→      const messageText = error instanceof Error ? error.message : "Network error";
491→      setErrorMessage(messageText);
492→      setIsLoading(false);
493→      return;
494→    } finally {
495→      setPendingFile(undefined);
496→    }
497→
498→    if (!response.ok) {
499→      const body = await response.text();
500→      setErrorMessage(body);
501→      setIsLoading(false);
502→      return;
503→    }
504→
505→    const payload = (await response.json()) as ChatMessageResponse;
506→    const isNewConversation = !backendConversationId;
507→    setBackendConversationId(payload.conversationId);
508→    if (isNewConversation) {
509→      setActiveConversationId(payload.conversationId);
510→    }
511→
512→    if (streamRef.current) {
513→      streamRef.current.close();
514→      streamRef.current = undefined;
515→    }
516→
517→    let streamedText = "";
518→
519→    const stream = new EventSource(payload.streamUrl);
520→    streamRef.current = stream;
521→
522→    stream.onmessage = (messageEvent) => {
523→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
524→
525→      if (parsed.type === "token") {
526→        streamedText = `${streamedText}${parsed.token}`;
527→        setSessions((existing) =>
528→          existing.map((session) =>
529→            session.id === activeSessionId
530→              ? {
531→                  ...session,
532→                  conversations: session.conversations.map((conversation) =>
533→                    conversation.id === clientMessageId
534→                      ? {
535→                          ...conversation,
536→                          response: streamedText,
537→                          updatedAt: new Date(),
538→                        }
539→                      : conversation,
540→                  ),
541→                }
542→              : session,
543→          ),
544→        );
545→        return;
546→      }
547→
548→      if (parsed.type === "assistant_message") {
549→        streamedText = parsed.text;
550→        setSuggestions(
551→          (parsed.suggestions ?? []).map((content, index) => ({
552→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
553→            content,
554→          })),
555→        );
556→        setSessions((existing) =>
557→          existing.map((session) =>
558→            session.id === activeSessionId
559→              ? {
560→                  ...session,
561→                  conversations: session.conversations.map((conversation) =>
562→                    conversation.id === clientMessageId
563→                      ? {
564→                          ...conversation,
565→                          response: streamedText,
566→                          updatedAt: new Date(),
567→                        }
568→                      : conversation,
569→                  ),
570→                }
571→              : session,
572→          ),
573→        );
574→        return;
575→      }
576→
577→      if (parsed.type === "onboarding_seed") {
578→        setSeedItems((existing) => {
579→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
580→          for (const seed of parsed.seeds) {
581→            deduped.set(`${seed.id}:${seed.sourceKind}:${seed.sourceId}`, seed);
582→          }
583→          return [...deduped.values()];
584→        });
585→        return;
586→      }
587→
588→      if (parsed.type === "onboarding_state") {
589→        setWorkspace((existing) =>
590→          existing
591→            ? {
592→                ...existing,
593→                onboardingState: parsed.onboardingState,
594→                onboardingComplete: parsed.onboardingState === "complete",
595→              }
596→            : existing,
597→        );
598→        return;
599→      }
600→
601→      if (parsed.type === "error") {
602→        setErrorMessage(parsed.error);
603→        setIsLoading(false);
604→        stream.close();
605→        streamRef.current = undefined;
606→        return;
607→      }
608→
609→      if (parsed.type === "done") {
610→        setSessions((existing) =>
611→          existing.map((session) =>
612→            session.id === activeSessionId
613→              ? {
614→                  ...session,
615→                  updatedAt: new Date(),
616→                  conversations: session.conversations.map((conversation) =>
617→                    conversation.id === clientMessageId
618→                      ? {
619→                          ...conversation,
620→                          response: streamedText,
621→                          updatedAt: new Date(),
622→                        }
623→                      : conversation,
624→                  ),
625→                }
626→              : session,
627→          ),
628→        );
629→
630→        setIsLoading(false);
631→        stream.close();
632→        streamRef.current = undefined;
633→
634→        // Refresh sidebar after stream completes
635→        if (workspace) {
636→          void refreshSidebar(workspace.id);
637→        }
638→      }
639→    };
640→
641→    stream.onerror = () => {
642→      setErrorMessage("SSE stream disconnected");
643→      setIsLoading(false);
644→      stream.close();
645→      streamRef.current = undefined;
646→    };
647→  }
