 10→export type ServerConfig = {
 11→  openRouterApiKey: string;
 12→  assistantModelId: string;
 13→  extractionModelId: string;
 14→  embeddingModelId: string;
 15→  embeddingDimension: number;
 16→  extractionStoreThreshold: number;
 17→  extractionDisplayThreshold: number;
 18→  openRouterReasoning?: OpenRouterReasoningOptions;
 19→  surrealUrl: string;
 20→  surrealUsername: string;
 21→  surrealPassword: string;
 22→  surrealNamespace: string;
 23→  surrealDatabase: string;
 24→  port: number;
 25→};
 26→
 27→export function loadServerConfig(): ServerConfig {
 28→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 29→
 30→  const extractionStoreThreshold = parseUnitInterval(
 31→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 32→    "EXTRACTION_STORE_THRESHOLD",
 33→  );
 34→
 35→  const extractionDisplayThreshold = parseUnitInterval(
 36→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 37→    "EXTRACTION_DISPLAY_THRESHOLD",
 38→  );
 39→
 40→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 41→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 42→  }
 43→
 44→  const assistantModelId = requireEnv("ASSISTANT_MODEL");
 45→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 46→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 47→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 48→
 49→  const surrealUrl = requireEnv("SURREAL_URL");
 50→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 51→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 52→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 53→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 54→
 55→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 56→
 57→  return {
 58→    openRouterApiKey,
 59→    assistantModelId,
 60→    extractionModelId,
 61→    embeddingModelId,
 62→    embeddingDimension,
 63→    extractionStoreThreshold,
 64→    extractionDisplayThreshold,
 65→    openRouterReasoning: parseOpenRouterReasoning(),
 66→    surrealUrl,
 67→    surrealUsername,
 68→    surrealPassword,
 69→    surrealNamespace,
 70→    surrealDatabase,
 71→    port,
 72→  };
 73→}
 74→
 75→function requireEnv(name: string): string {
 76→  const value = Bun.env[name];
 77→  if (!value || value.trim().length === 0) {
 78→    throw new Error(`${name} is required`);
 79→  }
 80→
 81→  return value;
 82→}
 83→
 84→function parsePositiveInteger(value: string, envName: string): number {
 85→  const parsed = Number(value);
 86→  if (!Number.isInteger(parsed) || parsed < 1) {
 87→    throw new Error(`${envName} must be a positive integer`);
 88→  }
 89→  return parsed;
 90→}
 91→
 92→function parseUnitInterval(value: string, envName: string): number {
 93→  const parsed = Number(value);
 94→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
 95→    throw new Error(`${envName} must be a number between 0 and 1`);
 96→  }
 97→
 98→  return parsed;
 99→}
100→
101→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
102→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
103→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
104→
105→  if (!effortValue && !maxTokensValue) {
106→    return undefined;
107→  }
108→
109→  const reasoning: OpenRouterReasoningOptions = {};
110→
111→  if (effortValue) {
112→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
113→
114→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
115→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
116→    }
117→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
118→  }
119→
120→  if (maxTokensValue) {
121→    const parsed = Number(maxTokensValue);
122→    if (!Number.isFinite(parsed) || parsed < 1) {
123→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
124→    }
125→    reasoning.max_tokens = parsed;
126→  }
127→
128→  return reasoning;
129→}
