228→        { workspace: workspaceRecord, project: entityRecord },
229→      )
230→      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();
231→
232→    return rows.length > 0;
233→  }
234→
235→  if (table === "person") {
236→    const [rows] = await surreal
237→      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
238→        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
239→        { workspace: workspaceRecord, person: entityRecord },
240→      )
241→      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();
242→
243→    return rows.length > 0;
244→  }
245→
246→  if (table === "feature") {
247→    const [rows] = await surreal
248→      .query<[Array<{ id: RecordId<"feature", string> }>]>(
249→        [
250→          "SELECT id",
251→          "FROM feature",
252→          "WHERE id = $feature",
253→          "AND id IN (",
254→          "  SELECT VALUE out",
255→          "  FROM has_feature",
256→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
257→          ");",
258→        ].join(" "),
259→        { workspace: workspaceRecord, feature: entityRecord },
260→      )
261→      .collect<[Array<{ id: RecordId<"feature", string> }>]>();
262→
263→    return rows.length > 0;
264→  }
265→
266→  if (table === "task" || table === "decision" || table === "question") {
267→    const [rows] = await surreal
268→      .query<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>(
269→        [
270→          "SELECT id",
271→          `FROM ${table}`,
272→          "WHERE id = $entity",
273→          "AND (",
274→          "  id IN (",
275→          "    SELECT VALUE `in`",
276→          "    FROM belongs_to",
277→          "    WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
278→          "  )",
279→          "  OR source_message IN (",
280→          "    SELECT VALUE id",
281→          "    FROM message",
282→          "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
283→          "  )",
284→          ");",
285→        ].join(" "),
286→        { workspace: workspaceRecord, entity: entityRecord },
287→      )
288→      .collect<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>();
289→
290→    return rows.length > 0;
291→  }
292→
293→  return false;
294→}
