296→export async function listConversationEntities(input: {
297→  surreal: Surreal;
298→  conversationRecord: RecordId<"conversation", string>;
299→  workspaceRecord: RecordId<"workspace", string>;
300→  limit: number;
301→}): Promise<ConversationEntity[]> {
302→  const [rows] = await input.surreal
303→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
304→      [
305→        "SELECT `in`, out, confidence, extracted_at",
306→        "FROM extraction_relation",
307→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
308→        "ORDER BY extracted_at DESC",
309→        "LIMIT $limit;",
310→      ].join(" "),
311→      {
312→        conversation: input.conversationRecord,
313→        limit: input.limit,
314→      },
315→    )
316→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
317→
318→  const items: ConversationEntity[] = [];
319→  const seen = new Set<string>();
320→
321→  for (const row of rows) {
322→    const table = row.out.table.name as GraphEntityTable;
323→    if (
324→      table !== "workspace" &&
325→      table !== "project" &&
326→      table !== "person" &&
327→      table !== "feature" &&
328→      table !== "task" &&
329→      table !== "decision" &&
330→      table !== "question"
331→    ) {
332→      continue;
333→    }
334→
335→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
336→    if (!scoped) {
337→      continue;
338→    }
339→
340→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
341→    if (seen.has(entityKey)) {
342→      continue;
343→    }
344→
345→    const name = await readEntityName(input.surreal, row.out);
346→    if (!name) {
347→      continue;
348→    }
349→
350→    items.push({
351→      id: toRecordIdString(row.out),
352→      kind: table,
353→      name,
354→      confidence: row.confidence,
355→      sourceMessageId: toRecordIdString(row.in),
356→    });
357→    seen.add(entityKey);
358→  }
359→
360→  return items;
361→}
