 1→import type { ReagraphNode, ReagraphEdge, GraphResponse, EntityKind } from "../../shared/contracts";
 2→import type { GraphViewRawResult } from "./queries";
 3→
 4→export function entityColor(kind: EntityKind): string {
 5→  switch (kind) {
 6→    case "project": return "var(--entity-project)";
 7→    case "feature": return "var(--entity-feature)";
 8→    case "task": return "var(--entity-task)";
 9→    case "decision": return "var(--entity-decision)";
10→    case "question": return "var(--entity-question)";
11→    case "person": return "var(--entity-person)";
12→    case "workspace": return "var(--entity-project)";
13→  }
14→}
15→
16→function titleCase(s: string): string {
17→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
18→}
19→
20→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
21→  const connectionCounts = new Map<string, number>();
22→  for (const edge of raw.edges) {
23→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
24→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
25→  }
26→
27→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
28→    const kind = entity.table as EntityKind;
29→    return {
30→      id: entity.id,
31→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
32→      fill: entityColor(kind),
33→      data: {
34→        kind,
35→        connectionCount: connectionCounts.get(entity.id) ?? 0,
36→        status: undefined,
37→      },
38→    };
39→  });
40→
41→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
42→    id: edge.id,
43→    source: edge.fromId,
44→    target: edge.toId,
45→    label: titleCase(edge.kind.replace(/_/g, " ")),
46→    data: {
47→      type: edge.kind,
48→      confidence: edge.confidence,
49→    },
50→  }));
51→
52→  return { nodes, edges };
53→}
54→

