283→    setSeedItems(payload.seeds);
284→    setSuggestions(
285→      latestSuggestions.map((content, index) => ({
286→        id: `bootstrap-suggestion-${index}-${content}`,
287→        content,
288→      })),
289→    );
290→    setBackendConversationId(payload.conversationId);
291→    setActiveConversationId(payload.conversationId);
292→    setSidebar(payload.sidebar);
293→    setWorkspace({
294→      id: payload.workspaceId,
295→      name: payload.workspaceName,
296→      onboardingComplete: payload.onboardingComplete,
297→      onboardingState: payload.onboardingState,
298→      conversationId: payload.conversationId,
299→    });
300→  }
301→
302→  function onNewConversation() {
303→    setActiveConversationId(undefined);
304→    setBackendConversationId(undefined);
305→    setSessions([
306→      {
307→        id: "main",
308→        title: workspace?.name ?? "Workspace Chat",
309→        createdAt: new Date(),
310→        updatedAt: new Date(),
311→        conversations: [],
312→      },
313→    ]);
314→    setSuggestions([]);
315→    setErrorMessage(undefined);
316→  }
317→
318→  function onSelectConversation(conversationId: string) {
319→    if (conversationId === activeConversationId || isLoading || !workspace) {
320→      return;
321→    }
322→
323→    void loadConversation(workspace.id, conversationId);
324→  }
325→
326→  async function searchMentions(query: string): Promise<MentionItem[]> {
327→    if (!workspace) {
328→      return [];
329→    }
330→
331→    const response = await fetch(
332→      `/api/entities/search?q=${encodeURIComponent(query)}&workspaceId=${encodeURIComponent(workspace.id)}&limit=8`,
333→    );
334→    if (!response.ok) {
335→      throw new Error(`entity search failed: ${response.status}`);
336→    }
337→
338→    const rows = (await response.json()) as SearchEntityResponse[];
339→    return rows.map((row) => ({
340→      id: row.id,
341→      label: `${row.kind}: ${row.text.slice(0, 48)}`,
342→      description: `confidence ${row.confidence.toFixed(2)}`,
343→      value: `@${row.id}`,
344→    }));
345→  }
346→
347→  async function onCreateWorkspace(event: FormEvent<HTMLFormElement>) {
348→    event.preventDefault();
349→
350→    const name = createWorkspaceName.trim();
351→    const ownerDisplayName = createOwnerName.trim();
352→    if (isCreatingWorkspace) {
353→      return;
354→    }
355→
356→    if (!name || !ownerDisplayName) {
357→      setErrorMessage("Workspace name and owner display name are required");
358→      return;
359→    }
360→
361→    setErrorMessage(undefined);
362→    setIsCreatingWorkspace(true);
363→
364→    const requestBody: CreateWorkspaceRequest = {
365→      name,
366→      ownerDisplayName,
367→    };
368→
369→    try {
370→      const response = await fetch("/api/workspaces", {
371→        method: "POST",
372→        headers: {
373→          "Content-Type": "application/json",
374→        },
375→        body: JSON.stringify(requestBody),
376→      });
377→
378→      if (!response.ok) {
379→        const body = await response.text();
380→        setErrorMessage(body);
381→        return;
382→      }
383→
384→      const payload = (await response.json()) as Partial<CreateWorkspaceResponse>;
385→      if (typeof payload.workspaceId !== "string" || payload.workspaceId.trim().length === 0) {
386→        throw new Error("create workspace response is missing workspaceId");
387→      }
388→
389→      window.localStorage.setItem(ACTIVE_WORKSPACE_STORAGE_KEY, payload.workspaceId);
390→      await bootstrapWorkspace(payload.workspaceId);
391→      setCreateWorkspaceName("");
392→      setCreateOwnerName("");
393→    } catch (error) {
394→      const messageText = error instanceof Error ? error.message : "Workspace creation failed";
395→      setErrorMessage(messageText);
396→    } finally {
397→      setIsCreatingWorkspace(false);
398→    }
399→  }
400→
401→  function onUploadFile(file: File) {
402→    setPendingFile(file);
403→  }
404→
405→  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
406→    if (!pendingFile || isLoading) {
407→      return;
408→    }
409→
410→    const target = event.target;
411→    if (!(target instanceof Element)) {
412→      return;
413→    }
414→
415→    const sendButton = target.closest("button[title='Send']");
416→    if (!sendButton) {
417→      return;
418→    }
419→
420→    const currentMessage = chatInputRef.current?.getValue().trim() ?? "";
421→    if (currentMessage.length > 0) {
422→      return;
423→    }
424→
425→    event.preventDefault();
426→    event.stopPropagation();
427→    void onSendMessage("");
428→  }
429→
430→  async function onSendMessage(message: string, options?: { onboardingAction?: OnboardingAction }) {
431→    if (isLoading || !workspace) {
432→      return;
433→    }
434→
435→    const text = message.trim();
436→    if (!text && !pendingFile) {
437→      return;
438→    }
439→
440→    setErrorMessage(undefined);
441→    setIsLoading(true);
442→    setSuggestions([]);
443→
444→    const clientMessageId = crypto.randomUUID();
445→    const currentAttachment = pendingFile;
446→
447→    setSessions((existing) =>
448→      existing.map((session) =>
449→        session.id === activeSessionId
450→          ? {
451→              ...session,
452→              updatedAt: new Date(),
453→              conversations: [
454→                ...session.conversations,
455→                {
456→                  id: clientMessageId,
457→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
458→                  createdAt: new Date(),
459→                  ...(currentAttachment
460→                    ? {
461→                        files: [
462→                          {
463→                            name: currentAttachment.name,
464→                            type: currentAttachment.type,
465→                            size: currentAttachment.size,
466→                          },
467→                        ],
468→                      }
469→                    : {}),
470→                },
471→              ],
472→            }
473→          : session,
474→      ),
475→    );
476→
477→    let response: Response;
478→    try {
479→      if (currentAttachment) {
480→        const formData = new FormData();
481→        formData.set("clientMessageId", clientMessageId);
482→        formData.set("workspaceId", workspace.id);
483→        formData.set("text", text);
484→        if (backendConversationId) {
485→          formData.set("conversationId", backendConversationId);
486→        }
487→        if (options?.onboardingAction) {
488→          formData.set("onboardingAction", options.onboardingAction);
489→        }
490→        formData.set("file", currentAttachment);
491→
492→        response = await fetch("/api/chat/messages", {
493→          method: "POST",
494→          body: formData,
495→        });
496→      } else {
497→        response = await fetch("/api/chat/messages", {
498→          method: "POST",
499→          headers: {
500→            "Content-Type": "application/json",
501→          },
502→          body: JSON.stringify({
503→            clientMessageId,
504→            workspaceId: workspace.id,
505→            text,
506→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
507→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
508→          }),
509→        });
510→      }
511→    } catch (error) {
512→      const messageText = error instanceof Error ? error.message : "Network error";
513→      setErrorMessage(messageText);
514→      setIsLoading(false);
515→      return;
516→    } finally {
517→      setPendingFile(undefined);
518→    }
519→
520→    if (!response.ok) {
521→      const body = await response.text();
522→      setErrorMessage(body);
523→      setIsLoading(false);
524→      return;
525→    }
526→
527→    const payload = (await response.json()) as ChatMessageResponse;
528→    const isNewConversation = !backendConversationId;
529→    setBackendConversationId(payload.conversationId);
530→    if (isNewConversation) {
531→      setActiveConversationId(payload.conversationId);
532→    }
533→
534→    if (streamRef.current) {
535→      streamRef.current.close();
536→      streamRef.current = undefined;
537→    }
538→
539→    let streamedText = "";
540→
541→    const stream = new EventSource(payload.streamUrl);
542→    streamRef.current = stream;
543→
544→    stream.onmessage = (messageEvent) => {
545→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
546→
547→      if (parsed.type === "token") {
548→        streamedText = `${streamedText}${parsed.token}`;
549→        setSessions((existing) =>
550→          existing.map((session) =>
551→            session.id === activeSessionId
552→              ? {
553→                  ...session,
554→                  conversations: session.conversations.map((conversation) =>
555→                    conversation.id === clientMessageId
556→                      ? {
557→                          ...conversation,
558→                          response: streamedText,
559→                          updatedAt: new Date(),
560→                        }
561→                      : conversation,
562→                  ),
563→                }
564→              : session,
565→          ),
566→        );
567→        return;
568→      }
569→
570→      if (parsed.type === "assistant_message") {
571→        streamedText = parsed.text;
572→        setSuggestions(
573→          (parsed.suggestions ?? []).map((content, index) => ({
574→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
575→            content,
576→          })),
577→        );
578→        setSessions((existing) =>
579→          existing.map((session) =>
580→            session.id === activeSessionId
581→              ? {
582→                  ...session,
583→                  conversations: session.conversations.map((conversation) =>
584→                    conversation.id === clientMessageId
585→                      ? {
586→                          ...conversation,
587→                          response: streamedText,
588→                          updatedAt: new Date(),
589→                        }
590→                      : conversation,
591→                  ),
592→                }
593→              : session,
594→          ),
595→        );
596→        return;
597→      }
598→
599→      if (parsed.type === "onboarding_seed") {
600→        setSeedItems((existing) => {
601→          const deduped = new Map(existing.map((item) => [`${item.id}:${item.sourceKind}:${item.sourceId}`, item]));
602→          for (const seed of parsed.seeds) {
603→            deduped.set(`${seed.id}:${seed.sourceKind}:${seed.sourceId}`, seed);
604→          }
605→          return [...deduped.values()];
606→        });
607→        return;
608→      }
609→
610→      if (parsed.type === "onboarding_state") {
611→        setWorkspace((existing) =>
612→          existing
613→            ? {
614→                ...existing,
615→                onboardingState: parsed.onboardingState,
616→                onboardingComplete: parsed.onboardingState === "complete",
617→              }
618→            : existing,
619→        );
620→        return;
621→      }
622→
623→      if (parsed.type === "error") {
624→        setErrorMessage(parsed.error);
625→        setIsLoading(false);
626→        stream.close();
627→        streamRef.current = undefined;
628→        return;
629→      }
630→
631→      if (parsed.type === "done") {
632→        setSessions((existing) =>
633→          existing.map((session) =>
634→            session.id === activeSessionId
635→              ? {
636→                  ...session,
637→                  updatedAt: new Date(),
638→                  conversations: session.conversations.map((conversation) =>
639→                    conversation.id === clientMessageId
640→                      ? {
641→                          ...conversation,
642→                          response: streamedText,
643→                          updatedAt: new Date(),
644→                        }
645→                      : conversation,
646→                  ),
647→                }
648→              : session,
649→          ),
650→        );
651→
652→        setIsLoading(false);
653→        stream.close();
654→        streamRef.current = undefined;
655→
656→        // Refresh sidebar after stream completes
657→        if (workspace) {
658→          void refreshSidebar(workspace.id);
659→        }
660→      }
661→    };
662→
663→    stream.onerror = () => {
664→      setErrorMessage("SSE stream disconnected");
665→      setIsLoading(false);
666→      stream.close();
667→      streamRef.current = undefined;
668→    };
669→  }
670→
671→  function onStopMessage() {
672→    if (!streamRef.current) {
673→      return;
674→    }
675→
676→    streamRef.current.close();
677→    streamRef.current = undefined;
678→    setIsLoading(false);
679→  }
680→
681→  if (!workspace) {
682→    return (
683→      <section className="workspace-setup">
684→        <h2>Create Workspace</h2>
685→        <p>Start with workspace name and owner identity. Onboarding continues in chat.</p>
686→        <form onSubmit={onCreateWorkspace} className="workspace-form">
687→          <label>
688→            Workspace name
689→            <input
690→              value={createWorkspaceName}
691→              onChange={(event) => setCreateWorkspaceName(event.target.value)}
692→              placeholder="Acme Labs"
693→              required
694→            />
695→          </label>
696→          <label>
697→            Owner display name
698→            <input
699→              value={createOwnerName}
700→              onChange={(event) => setCreateOwnerName(event.target.value)}
701→              placeholder="Marcus"
702→              required
703→            />
704→          </label>
705→          <button type="submit" disabled={!canCreateWorkspace || isCreatingWorkspace || isBootstrapping}>
706→            {isCreatingWorkspace ? "Creating..." : "Create Workspace"}
707→          </button>
708→        </form>
709→        {errorMessage ? <p className="error-message">{errorMessage}</p> : undefined}
710→      </section>
711→    );
712→  }
713→
714→  return (
715→    <section className="reachat-page">
716→      <div className="workspace-toolbar">
717→        <div>
718→          <strong>{workspace.name}</strong>
719→        </div>
720→        <button type="button" className="seed-toggle" onClick={() => setIsSeedPanelOpen((current) => !current)}>
721→          {isSeedPanelOpen ? "Hide live graph seed" : "Show live graph seed"} ({seedItems.length})
722→        </button>
723→        {pendingFile ? (
724→          <div className="pending-file">
725→            Attached: {pendingFile.name}
726→            <button type="button" onClick={() => setPendingFile(undefined)}>
727→              Clear
728→            </button>
729→          </div>
730→        ) : undefined}
731→      </div>
732→
733→      <div className="workspace-layout">
734→        <aside className="conversation-sidebar">
735→          <button
736→            type="button"
737→            className="sidebar-new-conversation"
738→            onClick={onNewConversation}
739→            disabled={isLoading}
740→          >
741→            New conversation
742→          </button>
743→
744→          {sidebar?.groups.map((group) => (
745→            <div key={group.projectId} className="sidebar-project-group">
746→              <div className="sidebar-project-header">
747→                <span className="sidebar-project-name">{group.projectName}</span>
748→                <span className="sidebar-project-count">{group.conversations.length}</span>
749→              </div>
750→              {group.featureActivity.length > 0 ? (
751→                <div className="sidebar-feature-activity">
752→                  {group.featureActivity.map((feature) => (
753→                    <span key={feature.featureId} className="sidebar-feature-chip">
754→                      {feature.featureName}
755→                    </span>
756→                  ))}
757→                </div>
758→              ) : undefined}
759→              <ul className="sidebar-conversation-list">
760→                {group.conversations.map((conv) => (
761→                  <li key={conv.id}>
762→                    <button
763→                      type="button"
764→                      className={`sidebar-conversation-item${conv.id === activeConversationId ? " sidebar-conversation-item--active" : ""}`}
765→                      onClick={() => onSelectConversation(conv.id)}
766→                    >
767→                      {conv.title}
768→                    </button>
769→                  </li>
770→                ))}
771→              </ul>
772→            </div>
773→          ))}
774→
775→          {sidebar && sidebar.unlinked.length > 0 ? (
776→            <div className="sidebar-project-group">
777→              <div className="sidebar-project-header">
778→                <span className="sidebar-project-name sidebar-unlinked-label">Unlinked</span>
779→                <span className="sidebar-project-count">{sidebar.unlinked.length}</span>
780→              </div>
781→              <ul className="sidebar-conversation-list">
782→                {sidebar.unlinked.map((conv) => (
783→                  <li key={conv.id}>
784→                    <button
785→                      type="button"
786→                      className={`sidebar-conversation-item${conv.id === activeConversationId ? " sidebar-conversation-item--active" : ""}`}
787→                      onClick={() => onSelectConversation(conv.id)}
788→                    >
789→                      {conv.title}
790→                    </button>
791→                  </li>
792→                ))}
793→              </ul>
794→            </div>
795→          ) : undefined}
796→        </aside>
797→
798→        <div className={`chat-main${isSeedPanelOpen ? " chat-main--with-seeds" : ""}`}>
799→          <Chat
800→            viewType="chat"
801→            sessions={sessions}
802→            activeSessionId={activeSession.id}
803→            components={chatComponentCatalog}
804→            isLoading={isLoading}
805→            onSendMessage={onSendMessage}
806→            onStopMessage={onStopMessage}
807→            onFileUpload={onUploadFile}
808→          >
809→            <SessionMessagePanel>
810→              <SessionMessagesHeader>
811→                <div className="reachat-header">Workspace Chat + Extraction</div>
812→              </SessionMessagesHeader>
813→              <SessionMessages />
814→              <ChatSuggestions
815→                suggestions={suggestions}
816→                onSuggestionClick={(suggestion) => {
817→                  void onSendMessage(suggestion);
818→                }}
819→              />
820→              {workspace.onboardingState === "summary_pending" ? (
821→                <div className="onboarding-action-buttons">
822→                  <button
823→                    type="button"
824→                    disabled={isLoading}
825→                    onClick={() =>
826→                      void onSendMessage("Looks good, let's go.", {
827→                        onboardingAction: "finalize_onboarding",
828→                      })}
829→                  >
830→                    Looks good, let's go
831→                  </button>
832→                  <button
833→                    type="button"
834→                    disabled={isLoading}
835→                    onClick={() =>
836→                      void onSendMessage("I want to add more.", {
837→                        onboardingAction: "continue_onboarding",
838→                      })}
839→                  >
840→                    I want to add more
841→                  </button>
842→                </div>
843→              ) : undefined}
844→              <div onClickCapture={onChatInputClickCapture}>
845→                <ChatInput
846→                  ref={chatInputRef}
847→                  placeholder="Discuss tasks, decisions, and questions..."
848→                  allowedFiles={[".md", ".txt"]}
849→                  mentions={{
850→                    onSearch: searchMentions,
851→                  }}
852→                  commands={{
853→                    items: COMMAND_ITEMS,
854→                  }}
855→                />
856→              </div>
857→            </SessionMessagePanel>
858→          </Chat>
859→
860→          {isSeedPanelOpen ? (
861→            <aside className="seed-panel">
862→              <h3>Live Graph Seed</h3>
863→              <p>Entities extracted during onboarding and document ingestion.</p>
864→              <ul>
865→                {seedItems.map((seed) => (
866→                  <li key={`${seed.id}:${seed.sourceKind}:${seed.sourceId}`}>
867→                    <button
868→                      type="button"
869→                    >
870→                      <span className="seed-kind">{seed.kind}</span>
871→                      <span className="seed-text">{seed.text}</span>
872→                      <span className="seed-meta">
873→                        {seed.confidence.toFixed(2)} · {seed.sourceKind}
874→                      </span>
875→                      {seed.sourceLabel ? <span className="seed-label">{seed.sourceLabel}</span> : undefined}
876→                    </button>
877→                  </li>
878→                ))}
879→              </ul>
880→            </aside>
881→          ) : undefined}
882→        </div>
883→      </div>
884→
885→      {errorMessage ? <p className="error-message">{errorMessage}</p> : undefined}
886→    </section>
887→  );
888→}
